html:
{% set risque_couleur = {'Faible': '#1a7f4b', 'Moyen': '#c07a00', 'Élevé': '#b91c1c', 'Critique': '#7c0000'} %}
{% set risque_bg = {'Faible': '#dcfce7', 'Moyen': '#fef9c3', 'Élevé': '#fee2e2', 'Critique': '#fce7f3'} %}
{% set decision_couleur = {'GO': '#1a7f4b', 'NO GO': '#b91c1c', 'GO sous réserve': '#c07a00'} %}

<style>
  @page {
    size: A4;
    margin: 18mm 15mm 22mm 15mm;
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    font-size: 9.5pt;
    color: #1a1a2e;
    line-height: 1.45;
  }

  /* ── EN-TÊTE ────────────────────────────────── */
  .header {
    background: #0d1b2a;
    color: #fff;
    padding: 14px 20px 12px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-radius: 3px 3px 0 0;
  }
  .header-left .brand { font-size: 13pt; font-weight: 700; letter-spacing: 0.5px; }
  .header-left .tagline { font-size: 7pt; color: #8da9c4; margin-top: 2px; }
  .header-right { text-align: right; }
  .header-right .doc-type {
    background: #1e3a5f;
    padding: 4px 10px;
    border-radius: 3px;
    font-size: 8pt;
    font-weight: 600;
    letter-spacing: 0.8px;
    text-transform: uppercase;
  }
  .header-right .doc-ref { font-size: 7.5pt; color: #8da9c4; margin-top: 4px; }

  /* ── BANDEAU DÉCISION ─────────────────────────── */
  .decision-banner {
    margin: 0;
    padding: 10px 20px;
    border-left: 5px solid #0d1b2a;
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: #f0f4f8;
  }
  .decision-badge {
    display: inline-block;
    padding: 5px 18px;
    border-radius: 20px;
    font-weight: 700;
    font-size: 11pt;
    letter-spacing: 0.5px;
  }
  .decision-date { font-size: 8pt; color: #555; }

  /* ── SECTION TITRE ───────────────────────────── */
  .section-title {
    font-size: 8pt;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #0d1b2a;
    border-bottom: 2px solid #0d1b2a;
    padding-bottom: 3px;
    margin: 14px 0 8px;
  }

  /* ── GRILLE ──────────────────────────────────── */
  .grid { display: flex; gap: 10px; margin-bottom: 8px; }
  .grid-col { flex: 1; }
  .field-row { margin-bottom: 6px; }
  .field-label {
    font-size: 7.5pt;
    color: #666;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 1px;
  }
  .field-value {
    font-size: 9.5pt;
    color: #1a1a2e;
    font-weight: 500;
  }
  .field-value.empty { color: #aaa; font-style: italic; font-weight: 400; }

  /* ── BADGE RISQUE ────────────────────────────── */
  .risque-badge {
    display: inline-block;
    padding: 3px 12px;
    border-radius: 20px;
    font-weight: 700;
    font-size: 9pt;
  }

  /* ── SCORE ──────────────────────────────────── */
  .score-row { display: flex; gap: 20px; align-items: center; margin: 8px 0; }
  .score-box {
    text-align: center;
    background: #f0f4f8;
    border: 1px solid #d0dce8;
    border-radius: 4px;
    padding: 8px 16px;
    min-width: 80px;
  }
  .score-box .score-num { font-size: 20pt; font-weight: 700; color: #0d1b2a; }
  .score-box .score-label { font-size: 7pt; color: #666; text-transform: uppercase; letter-spacing: 0.5px; }

  /* ── TABLEAU ─────────────────────────────────── */
  table.data-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 8.5pt;
    margin-bottom: 8px;
  }
  table.data-table th {
    background: #0d1b2a;
    color: #fff;
    padding: 5px 8px;
    text-align: left;
    font-weight: 600;
    font-size: 8pt;
  }
  table.data-table td {
    padding: 5px 8px;
    border-bottom: 1px solid #e5ecf3;
    vertical-align: top;
  }
  table.data-table tr:nth-child(even) td { background: #f7fafd; }
  table.data-table .empty-row td {
    text-align: center;
    color: #aaa;
    font-style: italic;
    padding: 10px;
  }

  /* ── RÉSERVES ────────────────────────────────── */
  .reserves-box {
    background: #fffbeb;
    border: 1px solid #f59e0b;
    border-left: 4px solid #f59e0b;
    border-radius: 3px;
    padding: 10px 12px;
    font-size: 9pt;
    white-space: pre-wrap;
    margin-top: 6px;
  }

  /* ── COMMENTAIRE INTERNE ─────────────────────── */
  .commentaire-box {
    background: #f0f4f8;
    border: 1px solid #c5d5e8;
    border-left: 4px solid #0d1b2a;
    border-radius: 3px;
    padding: 10px 12px;
    font-size: 9pt;
    white-space: pre-wrap;
    margin-top: 6px;
  }

  /* ── PIED DE PAGE ────────────────────────────── */
  .footer {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: #0d1b2a;
    color: #8da9c4;
    font-size: 7pt;
    padding: 5px 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
  }
  .footer .confidential {
    background: #b91c1c;
    color: #fff;
    padding: 2px 8px;
    border-radius: 2px;
    font-weight: 700;
    letter-spacing: 0.5px;
    font-size: 6.5pt;
  }

  /* ── SÉPARATEUR ──────────────────────────────── */
  hr.divider {
    border: none;
    border-top: 1px solid #d0dce8;
    margin: 10px 0;
  }

  /* ── SIGNATURE ──────────────────────────────── */
  .signature-zone {
    display: flex;
    gap: 30px;
    margin-top: 20px;
  }
  .signature-block {
    flex: 1;
    text-align: center;
    border-top: 1px solid #0d1b2a;
    padding-top: 6px;
    font-size: 8pt;
    color: #555;
  }
</style>

<!-- EN-TÊTE -->
<div class="header">
  <div class="header-left">
    <div class="brand">AMOAMAN &amp; ASSOCIÉS</div>
    <div class="tagline">Cabinet de Conseil en Compliance &amp; Due Diligence</div>
  </div>
  <div class="header-right">
    <div class="doc-type">Avis Compliance</div>
    <div class="doc-ref">Réf. : {{ doc.name }}</div>
  </div>
</div>

<!-- BANDEAU DÉCISION -->
{% set dec_label = doc.decision_finale or 'En attente' %}
{% set dec_couleur = decision_couleur.get(dec_label, '#555') %}
<div class="decision-banner">
  <div>
    <span style="font-size:8pt;color:#666;display:block;margin-bottom:3px;">DÉCISION FINALE</span>
    <span class="decision-badge" style="background:{{ risque_bg.get(doc.categorie_risque, '#f0f4f8') }};color:{{ dec_couleur }};border:1.5px solid {{ dec_couleur }};">
      {{ dec_label }}
    </span>
  </div>
  <div class="decision-date">
    {% if doc.date_decision %}
      Rendu le {{ frappe.format(doc.date_decision, {'fieldtype': 'Datetime'}) }}
    {% else %}
      Date non renseignée
    {% endif %}
  </div>
</div>

<!-- SECTION 1 : INFORMATIONS GÉNÉRALES -->
<div class="section-title">1. Informations générales</div>
<div class="grid">
  <div class="grid-col">
    <div class="field-row">
      <div class="field-label">Nom du tiers</div>
      <div class="field-value">{{ doc.tiers_nom or '—' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Type de Due Diligence</div>
      <div class="field-value">{{ doc.dd_type or '—' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Pays</div>
      <div class="field-value">{{ doc.tiers_pays or '—' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Secteur d'activité</div>
      <div class="field-value">{{ doc.tiers_secteur or '—' }}</div>
    </div>
  </div>
  <div class="grid-col">
    <div class="field-row">
      <div class="field-label">Demandeur</div>
      <div class="field-value">{{ doc.demandeur_nom or '—' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Fonction</div>
      <div class="field-value">{{ doc.demandeur_fonction or '—' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Direction / Service</div>
      <div class="field-value">{{ doc.direction_metier or '—' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Montant du contrat</div>
      <div class="field-value">
        {% if doc.tiers_montant_contrat %}
          {{ frappe.format(doc.tiers_montant_contrat, {'fieldtype': 'Currency'}) }} FCFA
        {% else %}—{% endif %}
      </div>
    </div>
  </div>
</div>

<hr class="divider">

<!-- SECTION 2 : FACTEURS DE RISQUE -->
<div class="section-title">2. Facteurs de risque identifiés</div>
<div class="grid">
  <div class="grid-col">
    <div class="field-row">
      <div class="field-label">Interaction avec acteurs publics</div>
      <div class="field-value">{{ 'Oui' if doc.interaction_publique else 'Non' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Traitement de données personnelles</div>
      <div class="field-value">{{ 'Oui' if doc.donnees_personnelles else 'Non' }}</div>
    </div>
    <div class="field-row">
      <div class="field-label">Accès au Système d'Information</div>
      <div class="field-value">{{ 'Oui' if doc.acces_si else 'Non' }}</div>
    </div>
  </div>
  <div class="grid-col">
    <div class="score-row">
      <div class="score-box">
        <div class="score-num">{{ doc.score_brut or 0 }}</div>
        <div class="score-label">Score brut</div>
      </div>
      <div class="score-box">
        <div class="score-num">{{ doc.score_pondere or 0 }}</div>
        <div class="score-label">Score pondéré</div>
      </div>
      <div>
        <div class="field-label" style="margin-bottom:4px;">Catégorie de risque</div>
        {% set risque = doc.categorie_risque or '—' %}
        <span class="risque-badge"
          style="background:{{ risque_bg.get(risque, '#f0f4f8') }};color:{{ risque_couleur.get(risque, '#333') }};">
          {{ risque }}
        </span>
      </div>
    </div>
  </div>
</div>

<hr class="divider">

<!-- SECTION 3 : RÉPONSES AU QUESTIONNAIRE -->
<div class="section-title">3. Réponses au questionnaire</div>
<table class="data-table">
  <thead>
    <tr>
      <th style="width:55%">Question</th>
      <th style="width:20%">Réponse</th>
      <th style="width:25%">Commentaire</th>
    </tr>
  </thead>
  <tbody>
    {% if doc.answers %}
      {% for row in doc.answers %}
        <tr>
          <td>{{ row.question or '—' }}</td>
          <td>{{ row.reponse or '—' }}</td>
          <td>{{ row.commentaire or '' }}</td>
        </tr>
      {% endfor %}
    {% else %}
      <tr class="empty-row"><td colspan="3">Aucune réponse enregistrée</td></tr>
    {% endif %}
  </tbody>
</table>

<hr class="divider">

<!-- SECTION 4 : DOCUMENTS FOURNIS -->
<div class="section-title">4. Documents fournis</div>
<table class="data-table">
  <thead>
    <tr>
      <th style="width:50%">Document requis</th>
      <th style="width:20%">Statut</th>
      <th style="width:30%">Référence</th>
    </tr>
  </thead>
  <tbody>
    {% if doc.required_documents %}
      {% for row in doc.required_documents %}
        <tr>
          <td>{{ row.document_name or '—' }}</td>
          <td>{{ row.statut or '—' }}</td>
          <td>{{ row.reference or '' }}</td>
        </tr>
      {% endfor %}
    {% else %}
      <tr class="empty-row"><td colspan="3">Aucun document enregistré</td></tr>
    {% endif %}
  </tbody>
</table>

<hr class="divider">

<!-- SECTION 5 : AVIS COMPLIANCE -->
<div class="section-title">5. Avis du département Compliance</div>

{% if doc.commentaire_interne %}
  <div class="field-label" style="margin-bottom:4px;">Commentaire interne</div>
  <div class="commentaire-box">{{ doc.commentaire_interne }}</div>
{% else %}
  <div class="field-value empty">Aucun commentaire interne renseigné.</div>
{% endif %}

{% if doc.reserves %}
  <div class="field-label" style="margin-top:10px;margin-bottom:4px;">Réserves / Conditions</div>
  <div class="reserves-box">{{ doc.reserves }}</div>
{% endif %}

<!-- SIGNATURES -->
<div class="signature-zone">
  <div class="signature-block">
    Analyste Compliance<br>
    <strong>{{ doc.analyste_assigne or '_______________' }}</strong>
  </div>
  <div class="signature-block">
    Responsable Compliance<br>
    <strong>_______________</strong>
  </div>
  <div class="signature-block">
    Direction Générale<br>
    <strong>_______________</strong>
  </div>
</div>

<!-- PIED DE PAGE -->
<div class="footer">
  <span>AMOAMAN &amp; ASSOCIÉS — Document confidentiel</span>
  <span class="confidential">CONFIDENTIEL</span>
  <span>{{ frappe.format(frappe.utils.now(), {'fieldtype': 'Date'}) }} — Réf. {{ doc.name }}</span>
</div>
